#include <stdio.h>
#include <math.h>
int isPerfectSquare(int n) {
    int sqrt_n = sqrt(n);
    return (sqrt_n * sqrt_n == n);
}
int minOperations(int a[], int n) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (!isPerfectSquare(a[i])) {
            int j = 2;
            while (j * j <= a[i]) {
                if (a[i] % j == 0) {
                    a[i] /= j;
                    count++;
                } else {
                    j++;
                }
            }
        }
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        printf("%d\n", minOperations(a, n));
    }
    return 0;
}

